import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Box, Button, Flex, Heading, Spacer } from '@chakra-ui/react';

const Header = () => {
  const navigate = useNavigate();
  const authToken = localStorage.getItem('authToken');

  const handleLogout = () => {
    localStorage.removeItem('authToken');
    navigate('/');
  };

  return (
    <Box bg="teal.500" p={4} color="white">
      <Flex alignItems="center">
        <Heading as="h1" size="md">
          Workforce Tracker
        </Heading>
        <Spacer />
        <Button as={Link} to="/" colorScheme="teal" variant="outline" mr={2}>
          Login
        </Button>
        <Button as={Link} to="/signup" colorScheme="teal" variant="outline" mr={2}>
          Sign Up
        </Button>
        <Button as={Link} to="/task-tracker" colorScheme="teal" variant="outline" mr={2}>
          Task Tracker
        </Button>
        {authToken && (
          <Button as="a" href="/user-dashboard" target="_blank" rel="noopener noreferrer" colorScheme="teal" variant="outline" mr={2}>
            User Dashboard
          </Button>
        )}
        {authToken && (
          <Button onClick={handleLogout} colorScheme="teal" variant="outline">
            Logout
          </Button>
        )}
      </Flex>
    </Box>
  );
};

export default Header;
